import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Toaster, toast } from 'react-hot-toast';
import { 
  MapPin, 
  Clock, 
  Users, 
  AlertTriangle, 
  ThumbsUp, 
  Send,
  RefreshCw,
  Activity,
  Bike,
  Car,
  Phone,
  Award,
  Download,
  Info,
  Moon,
  Sun,
  TrendingUp,
  CheckCircle,
  AlertCircle,
  CreditCard,
  FileText,
  HelpCircle
} from 'lucide-react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

function App() {
  const [centers, setCenters] = useState([]);
  const [selectedCenter, setSelectedCenter] = useState(null);
  const [reports, setReports] = useState([]);
  const [currentStatus, setCurrentStatus] = useState(null);
  const [stats, setStats] = useState([]);
  const [requirements, setRequirements] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [prediction, setPrediction] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showReportForm, setShowReportForm] = useState(false);
  const [filter24Hours, setFilter24Hours] = useState(false);
  const [vehicleFilter, setVehicleFilter] = useState('all');
  const [darkMode, setDarkMode] = useState(false);
  const [reportData, setReportData] = useState({
    crowd_level: 'moderate',
    wait_time: 15,
    reporter_name: '',
    vehicle_type: 'motorcycle'
  });

  useEffect(() => {
    fetchAllData();
    const interval = setInterval(() => {
      if (selectedCenter) {
        refreshCenterData(selectedCenter.id);
      }
      fetchStats();
    }, 60000);
    return () => clearInterval(interval);
  }, [selectedCenter]);

  const fetchAllData = async () => {
    try {
      await Promise.all([
        fetchCenters(),
        fetchRequirements(),
        fetchAnnouncements(),
        fetchStats()
      ]);
    } catch (error) {
      toast.error('Failed to load some data');
    } finally {
      setLoading(false);
    }
  };

  const fetchCenters = async () => {
    try {
      let url = `${API_URL}/centers`;
      const params = new URLSearchParams();
      if (filter24Hours) params.append('is_24hours', 'true');
      if (vehicleFilter !== 'all') params.append('vehicle_type', vehicleFilter);
      if (params.toString()) url += '?' + params.toString();
      
      const res = await axios.get(url);
      setCenters(res.data);
      if (res.data.length > 0 && !selectedCenter) {
        setSelectedCenter(res.data[0]);
        refreshCenterData(res.data[0].id);
      }
    } catch (err) {
      toast.error('Failed to load centers');
    }
  };

  const fetchRequirements = async () => {
    try {
      const res = await axios.get(`${API_URL}/requirements`);
      setRequirements(res.data);
    } catch (err) {
      console.error('Failed to load requirements');
    }
  };

  const fetchAnnouncements = async () => {
    try {
      const res = await axios.get(`${API_URL}/announcements`);
      setAnnouncements(res.data);
    } catch (err) {
      console.error('Failed to load announcements');
    }
  };

  const fetchStats = async () => {
    try {
      const res = await axios.get(`${API_URL}/stats`);
      setStats(res.data);
    } catch (err) {
      console.error('Failed to load stats');
    }
  };

  const refreshCenterData = async (centerId) => {
    await Promise.all([
      fetchCenterStatus(centerId),
      fetchReports(centerId),
      fetchPrediction(centerId)
    ]);
  };

  const fetchCenterStatus = async (id) => {
    try {
      const res = await axios.get(`${API_URL}/centers/${id}/status`);
      setCurrentStatus(res.data);
    } catch (err) { console.error(err); }
  };

  const fetchReports = async (id) => {
    try {
      const res = await axios.get(`${API_URL}/centers/${id}/reports`);
      setReports(res.data);
    } catch (err) { console.error(err); }
  };

  const fetchPrediction = async (id) => {
    try {
      const res = await axios.get(`${API_URL}/predict/${id}`);
      setPrediction(res.data);
    } catch (err) { console.error(err); }
  };

  const handleCenterSelect = (center) => {
    setSelectedCenter(center);
    refreshCenterData(center.id);
  };

  const handleSubmitReport = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/reports`, {
        center_id: selectedCenter.id,
        ...reportData
      });
      toast.success('Report submitted! Thanks for helping others.');
      setShowReportForm(false);
      refreshCenterData(selectedCenter.id);
      setReportData({ 
        crowd_level: 'moderate', 
        wait_time: 15, 
        reporter_name: '',
        vehicle_type: 'motorcycle'
      });
    } catch (err) {
      toast.error('Failed to submit');
    }
  };

  const handleVerify = async (reportId) => {
    try {
      await axios.post(`${API_URL}/reports/${reportId}/verify`);
      toast.success('Verified! Thanks for confirming.');
      refreshCenterData(selectedCenter.id);
    } catch (err) {
      if (err.response?.status === 400) toast.error('Already verified');
      else toast.error('Verification failed');
    }
  };

  const getCrowdColor = (level) => {
    switch(level) {
      case 'quiet': return 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200';
      case 'moderate': return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200';
      case 'busy': return 'bg-orange-100 text-orange-800 dark:bg-orange-900 dark:text-orange-200';
      case 'very_busy': return 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200';
      default: return 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300';
    }
  };

  const getCrowdIcon = (level) => {
    switch(level) {
      case 'quiet': return '😊';
      case 'moderate': return '😐';
      case 'busy': return '😕';
      case 'very_busy': return '😫';
      default: return '❓';
    }
  };

  const getCrowdDescription = (level) => {
    switch(level) {
      case 'quiet': return 'No wait, walk-in immediately';
      case 'moderate': return 'Short wait (5-15 minutes)';
      case 'busy': return 'Long wait (15-30 minutes)';
      case 'very_busy': return 'Very long wait (30+ minutes)';
      default: return 'Unknown';
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffMinutes = Math.floor((now - date) / (1000 * 60));
    
    if (diffMinutes < 1) return 'Just now';
    if (diffMinutes < 60) return `${diffMinutes} min ago`;
    if (diffMinutes < 120) return '1 hour ago';
    if (diffMinutes < 1440) return `${Math.floor(diffMinutes / 60)} hours ago`;
    return date.toLocaleDateString();
  };

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    fetchCenters();
  }, [filter24Hours, vehicleFilter]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-900">
        <div className="text-center">
          <RefreshCw className="w-12 h-12 animate-spin text-blue-600 mx-auto mb-4" />
          <p className="text-gray-600 dark:text-gray-400">Loading M-Tag information...</p>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen ${darkMode ? 'dark' : ''}`}>
      <div className="bg-gray-50 dark:bg-gray-900 transition-colors duration-200">
        <Toaster position="top-right" />
        
        {/* Header */}
        <header className="bg-gradient-to-r from-blue-600 to-blue-800 text-white shadow-lg">
          <div className="container mx-auto px-4 py-6">
            <div className="flex justify-between items-center">
              <div>
                <h1 className="text-3xl font-bold flex items-center gap-2">
                  <Bike className="w-8 h-8" />
                  M-Tag Rush Checker
                </h1>
                <p className="text-blue-100 mt-2">
                  Real-time crowd updates • Now mandatory for motorcycles
                </p>
              </div>
              <button
                onClick={() => setDarkMode(!darkMode)}
                className="p-2 rounded-lg bg-blue-700 hover:bg-blue-600 transition"
              >
                {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
              </button>
            </div>
          </div>
        </header>

        {/* Announcement Banner */}
        {announcements.map(announcement => (
          <div key={announcement.id} className="bg-red-100 dark:bg-red-900 border-b border-red-200 dark:border-red-800">
            <div className="container mx-auto px-4 py-3">
              <div className="flex items-center gap-3">
                <AlertCircle className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0" />
                <p className="text-red-800 dark:text-red-200 font-medium">
                  {announcement.message}
                </p>
              </div>
            </div>
          </div>
        ))}

        <main className="container mx-auto px-4 py-8">
          {/* Quick Stats */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-blue-100 dark:bg-blue-900 rounded-lg">
                  <MapPin className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                </div>
                <div>
                  <p className="text-sm text-gray-500 dark:text-gray-400">Centers</p>
                  <p className="text-2xl font-bold dark:text-white">{centers.length}</p>
                </div>
              </div>
            </div>
            
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-green-100 dark:bg-green-900 rounded-lg">
                  <Clock className="w-5 h-5 text-green-600 dark:text-green-400" />
                </div>
                <div>
                  <p className="text-sm text-gray-500 dark:text-gray-400">24/7 Centers</p>
                  <p className="text-2xl font-bold dark:text-white">
                    {centers.filter(c => c.is_24hours === 1).length}
                  </p>
                </div>
              </div>
            </div>
            
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-purple-100 dark:bg-purple-900 rounded-lg">
                  <CreditCard className="w-5 h-5 text-purple-600 dark:text-purple-400" />
                </div>
                <div>
                  <p className="text-sm text-gray-500 dark:text-gray-400">Fee</p>
                  <p className="text-2xl font-bold dark:text-white">Rs. 250</p>
                </div>
              </div>
            </div>
            
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-orange-100 dark:bg-orange-900 rounded-lg">
                  <AlertTriangle className="w-5 h-5 text-orange-600 dark:text-orange-400" />
                </div>
                <div>
                  <p className="text-sm text-gray-500 dark:text-gray-400">Deadline</p>
                  <p className="text-2xl font-bold dark:text-white">Passed</p>
                </div>
              </div>
            </div>
          </div>

          {/* Requirements Card */}
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6 mb-8">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2 dark:text-white">
              <CheckCircle className="w-5 h-5 text-green-600" />
              Requirements for Motorcycle M-Tag
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-4">
              {requirements.map(req => (
                <div key={req.id} className="bg-gray-50 dark:bg-gray-700 rounded-lg p-4 text-center">
                  <div className="text-3xl mb-2">
                    {req.icon === 'id-card' && '🆔'}
                    {req.icon === 'book' && '📄'}
                    {req.icon === 'bike' && '🏍️'}
                    {req.icon === 'mount' && '📱'}
                    {req.icon === 'rupee' && '💰'}
                  </div>
                  <h3 className="font-medium text-sm dark:text-white">{req.title}</h3>
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{req.description}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Filters */}
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 mb-6">
            <div className="flex flex-wrap gap-4">
              <div className="flex items-center gap-2">
                <span className="text-sm font-medium dark:text-white">Vehicle:</span>
                <button
                  onClick={() => setVehicleFilter('all')}
                  className={`px-3 py-1 rounded-full text-sm flex items-center gap-1 ${
                    vehicleFilter === 'all' 
                      ? 'bg-blue-600 text-white' 
                      : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300'
                  }`}
                >
                  <Car className="w-3 h-3" /> All
                </button>
                <button
                  onClick={() => setVehicleFilter('motorcycle')}
                  className={`px-3 py-1 rounded-full text-sm flex items-center gap-1 ${
                    vehicleFilter === 'motorcycle' 
                      ? 'bg-blue-600 text-white' 
                      : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300'
                  }`}
                >
                  <Bike className="w-3 h-3" /> Motorcycles
                </button>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-sm font-medium dark:text-white">Hours:</span>
                <button
                  onClick={() => setFilter24Hours(!filter24Hours)}
                  className={`px-3 py-1 rounded-full text-sm ${
                    filter24Hours 
                      ? 'bg-blue-600 text-white' 
                      : 'bg-gray-100 dark:bg-gray-700 dark:text-gray-300'
                  }`}
                >
                  24/7 Only
                </button>
              </div>
            </div>
          </div>

          {/* Main Content */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Centers List */}
            <div className="lg:col-span-1">
              <div className="bg-white dark:bg-gray-800 rounded-lg shadow">
                <div className="p-4 border-b dark:border-gray-700">
                  <h2 className="font-semibold text-lg flex items-center gap-2 dark:text-white">
                    <MapPin className="w-5 h-5" /> M-Tag Centers
                  </h2>
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                    {centers.length} centers available
                  </p>
                </div>
                <div className="divide-y dark:divide-gray-700 max-h-[600px] overflow-y-auto">
                  {centers.map(center => {
                    const centerStat = stats.find(s => s.id === center.id);
                    return (
                      <button
                        key={center.id}
                        onClick={() => handleCenterSelect(center)}
                        className={`w-full text-left p-4 hover:bg-gray-50 dark:hover:bg-gray-700 transition ${
                          selectedCenter?.id === center.id 
                            ? 'bg-blue-50 dark:bg-blue-900/20 border-l-4 border-blue-500' 
                            : ''
                        }`}
                      >
                        <div className="flex justify-between items-start">
                          <div>
                            <h3 className="font-medium dark:text-white">{center.name}</h3>
                            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{center.address}</p>
                            <div className="flex items-center gap-2 mt-2">
                              <div className={`flex items-center gap-1 text-xs ${
                                center.is_24hours ? 'text-green-600 dark:text-green-400' : 'text-gray-500'
                              }`}>
                                <Clock className="w-3 h-3" />
                                {center.hours}
                              </div>
                              {centerStat?.avg_wait_time && (
                                <span className="text-xs bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded">
                                  ⏱️ {Math.round(centerStat.avg_wait_time)} min avg
                                </span>
                              )}
                            </div>
                          </div>
                          {center.vehicle_type === 'motorcycle' && (
                            <span className="text-xs bg-blue-100 dark:bg-blue-900 text-blue-800 dark:text-blue-200 px-2 py-0.5 rounded-full">
                              <Bike className="w-3 h-3 inline" />
                            </span>
                          )}
                        </div>
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* Selected Center Details */}
            {selectedCenter && (
              <div className="lg:col-span-2 space-y-6">
                {/* Center Header */}
                <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h2 className="text-2xl font-bold dark:text-white">{selectedCenter.name}</h2>
                      <p className="text-gray-600 dark:text-gray-400 text-sm mt-1">{selectedCenter.address}</p>
                      <div className="flex items-center gap-3 mt-2">
                        <span className={`text-sm px-2 py-0.5 rounded-full ${
                          selectedCenter.is_24hours 
                            ? 'bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200' 
                            : 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-300'
                        }`}>
                          <Clock className="w-3 h-3 inline mr-1" />
                          {selectedCenter.hours}
                        </span>
                        {selectedCenter.contact && (
                          <span className="text-sm text-gray-500 dark:text-gray-400">
                            <Phone className="w-3 h-3 inline mr-1" />
                            {selectedCenter.contact}
                          </span>
                        )}
                      </div>
                    </div>
                    <button
                      onClick={() => setShowReportForm(!showReportForm)}
                      className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition flex items-center gap-2"
                    >
                      <Send className="w-4 h-4" /> Report Rush
                    </button>
                  </div>

                  {/* Current Status */}
                  {currentStatus && currentStatus.crowd_level !== 'unknown' && (
                    <div className="bg-gray-50 dark:bg-gray-700 rounded-lg p-4 mb-4">
                      <div className="flex justify-between items-start">
                        <div>
                          <h3 className="text-sm font-medium text-gray-500 dark:text-gray-400 mb-2">
                            Current Status
                          </h3>
                          <div className="flex items-center gap-4 flex-wrap">
                            <span className={`px-3 py-1 rounded-full text-sm font-medium ${getCrowdColor(currentStatus.crowd_level)}`}>
                              {getCrowdIcon(currentStatus.crowd_level)} {currentStatus.crowd_level.replace('_', ' ')}
                            </span>
                            <span className="text-gray-600 dark:text-gray-300">
                              Wait time: <strong className="dark:text-white">{currentStatus.wait_time} minutes</strong>
                            </span>
                            <span className="text-xs text-gray-400 dark:text-gray-500">
                              {formatDate(currentStatus.created_at)}
                            </span>
                          </div>
                          <p className="text-xs text-gray-500 dark:text-gray-400 mt-2">
                            {getCrowdDescription(currentStatus.crowd_level)}
                          </p>
                        </div>
                        
                        {/* Prediction */}
                        {prediction && prediction.predicted_level !== 'unknown' && (
                          <div className="bg-purple-50 dark:bg-purple-900/20 rounded-lg p-2 text-center">
                            <TrendingUp className="w-4 h-4 text-purple-600 dark:text-purple-400 mx-auto mb-1" />
                            <p className="text-xs text-purple-600 dark:text-purple-400 font-medium">
                              Predicted: {prediction.predicted_level}
                            </p>
                          </div>
                        )}
                      </div>
                    </div>
                  )}

                  {/* Report Form */}
                  {showReportForm && (
                    <form onSubmit={handleSubmitReport} className="bg-blue-50 dark:bg-blue-900/20 rounded-lg p-4 mb-4">
                      <h3 className="font-medium mb-3 dark:text-white">Report Current Situation</h3>
                      <div className="space-y-3">
                        <select
                          value={reportData.crowd_level}
                          onChange={e => setReportData({...reportData, crowd_level: e.target.value})}
                          className="w-full p-2 border rounded-lg dark:bg-gray-800 dark:border-gray-700 dark:text-white"
                          required
                        >
                          <option value="quiet">😊 Quiet (No wait)</option>
                          <option value="moderate">😐 Moderate (5-15 min)</option>
                          <option value="busy">😕 Busy (15-30 min)</option>
                          <option value="very_busy">😫 Very Busy (30+ min)</option>
                        </select>
                        
                        <input
                          type="number"
                          min="0"
                          max="180"
                          value={reportData.wait_time}
                          onChange={e => setReportData({...reportData, wait_time: parseInt(e.target.value)})}
                          className="w-full p-2 border rounded-lg dark:bg-gray-800 dark:border-gray-700 dark:text-white"
                          placeholder="Wait time (minutes)"
                          required
                        />
                        
                        <select
                          value={reportData.vehicle_type}
                          onChange={e => setReportData({...reportData, vehicle_type: e.target.value})}
                          className="w-full p-2 border rounded-lg dark:bg-gray-800 dark:border-gray-700 dark:text-white"
                        >
                          <option value="motorcycle">🏍️ Motorcycle</option>
                          <option value="car">🚗 Car</option>
                          <option value="both">Both</option>
                        </select>
                        
                        <input
                          type="text"
                          value={reportData.reporter_name}
                          onChange={e => setReportData({...reportData, reporter_name: e.target.value})}
                          className="w-full p-2 border rounded-lg dark:bg-gray-800 dark:border-gray-700 dark:text-white"
                          placeholder="Your name (optional)"
                        />
                        
                        <div className="flex gap-2">
                          <button type="submit" className="flex-1 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700">
                            Submit Report
                          </button>
                          <button 
                            type="button" 
                            onClick={() => setShowReportForm(false)} 
                            className="px-4 py-2 border rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 dark:text-white"
                          >
                            Cancel
                          </button>
                        </div>
                      </div>
                    </form>
                  )}

                  {/* Recent Reports */}
                  <div>
                    <h3 className="font-medium mb-3 dark:text-white">Recent Reports from This Location</h3>
                    <div className="space-y-3 max-h-96 overflow-y-auto">
                      {reports.length === 0 ? (
                        <p className="text-gray-500 dark:text-gray-400 text-center py-4">
                          No reports yet. Be the first to report the current rush!
                        </p>
                      ) : (
                        reports.map(report => (
                          <div key={report.id} className="border dark:border-gray-700 rounded-lg p-3">
                            <div className="flex justify-between items-start">
                              <div className="flex-1">
                                <div className="flex items-center gap-2 mb-2 flex-wrap">
                                  <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${getCrowdColor(report.crowd_level)}`}>
                                    {report.crowd_level.replace('_', ' ')}
                                  </span>
                                  <span className="text-sm text-gray-600 dark:text-gray-400">
                                    Wait: <strong>{report.wait_time} min</strong>
                                  </span>
                                  {report.vehicle_type === 'motorcycle' && (
                                    <span className="text-xs bg-blue-100 dark:bg-blue-900 text-blue-800 dark:text-blue-200 px-2 py-0.5 rounded-full">
                                      <Bike className="w-3 h-3 inline" /> Bike
                                    </span>
                                  )}
                                  {report.verified === 1 && (
                                    <span className="text-xs bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200 px-2 py-0.5 rounded-full flex items-center gap-1">
                                      <CheckCircle className="w-3 h-3" /> Verified
                                    </span>
                                  )}
                                </div>
                                <p className="text-xs text-gray-500 dark:text-gray-500">
                                  Reported by {report.reporter_name} • {formatDate(report.created_at)}
                                </p>
                              </div>
                              <button
                                onClick={() => handleVerify(report.id)}
                                className="flex items-center gap-1 text-sm text-gray-600 hover:text-blue-600 dark:text-gray-400 dark:hover:text-blue-400"
                              >
                                <ThumbsUp className="w-4 h-4" /> 
                                <span>{report.verification_count || 0}</span>
                              </button>
                            </div>
                          </div>
                        ))
                      )}
                    </div>
                  </div>
                </div>

                {/* Tips Card */}
                <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
                  <h3 className="font-medium mb-3 flex items-center gap-2 dark:text-white">
                    <AlertTriangle className="w-5 h-5 text-yellow-500" />
                    Important Tips for Motorcyclists
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <ul className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
                      <li className="flex items-start gap-2">
                        <span className="text-green-500">✓</span>
                        Visit 24/7 centers like 26 Number Chungi late at night (12 AM - 4 AM) to avoid queues
                      </li>
                      <li className="flex items-start gap-2">
                        <span className="text-green-500">✓</span>
                        Bring original CNIC and registration book/smart card
                      </li>
                      <li className="flex items-start gap-2">
                        <span className="text-green-500">✓</span>
                        Ensure your bike has official Excise-issued number plates
                      </li>
                    </ul>
                    <ul className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
                      <li className="flex items-start gap-2">
                        <span className="text-green-500">✓</span>
                        Tag attaches to speedometer/visor - must be visible
                      </li>
                      <li className="flex items-start gap-2">
                        <span className="text-green-500">✓</span>
                        Use One Network App to check balance and recharge
                      </li>
                      <li className="flex items-start gap-2">
                        <span className="text-red-500">⚠</span>
                        Enforcement started March 1, 2026 - fines apply
                      </li>
                    </ul>
                  </div>
                </div>

                {/* One Network App Card */}
                <div className="bg-gradient-to-r from-purple-50 to-blue-50 dark:from-purple-900/20 dark:to-blue-900/20 rounded-lg shadow p-6">
                  <div className="flex items-start gap-4">
                    <div className="p-3 bg-purple-600 rounded-lg">
                      <Download className="w-6 h-6 text-white" />
                    </div>
                    <div className="flex-1">
                      <h3 className="font-bold text-lg dark:text-white">One Network App</h3>
                      <p className="text-sm text-gray-600 dark:text-gray-400 mb-3">
                        Check balance, view trip history, and recharge your M-Tag
                      </p>
                      <div className="flex gap-3">
                        <a 
                          href="https://apps.apple.com/bt/app/m-tag-one-network/id1574366732" 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="text-sm bg-black text-white px-3 py-1 rounded-lg hover:bg-gray-800"
                        >
                          App Store
                        </a>
                        <a 
                          href="https://play.google.com/store/apps/details?hl=en_AU&id=com.ls.onenetwork.mtag" 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="text-sm bg-green-600 text-white px-3 py-1 rounded-lg hover:bg-green-700"
                        >
                          Google Play
                        </a>
                      </div>
                      <p className="text-xs text-gray-500 dark:text-gray-500 mt-2">
                        Support: 1313 • connect@onenetwork.pk
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </main>

        {/* Footer */}
        <footer className="bg-white dark:bg-gray-800 border-t dark:border-gray-700 mt-12">
          <div className="container mx-auto px-4 py-6">
            <div className="text-center text-gray-600 dark:text-gray-400 text-sm">
              <p>⚡ Community-powered M-Tag rush checker • Refreshes every 60 seconds</p>
              <p className="mt-2 text-xs">
                Data current as of March 2026 • M-Tag mandatory for all motorcycles entering Islamabad
              </p>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
}

export default App;
